import React, { useState } from "react";

const CalendarOverlay = ({ isOpen, onClose }) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  // Стан для вибраної дати (за замовчуванням 6 червня 2023 як на дизайні)
  const [selectedDate, setSelectedDate] = useState("June 6, 2023");

  if (!isOpen) return null;

  const daysOfWeek = ["MON", "TUE", "WED", "THU", "FRI", "SAT", "SUN"];
  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();
  const monthName = currentDate.toLocaleString("en-US", { month: "long" });

  const firstDayOfMonth = new Date(year, month, 1).getDay();
  const offset = firstDayOfMonth === 0 ? 6 : firstDayOfMonth - 1;
  const daysInMonth = new Date(year, month + 1, 0).getDate();

  const dates = [];
  for (let i = 0; i < offset; i++) dates.push("");
  for (let d = 1; d <= daysInMonth; d++) dates.push(d);

  const changeMonth = (offset) => {
    setCurrentDate(new Date(year, month + offset, 1));
  };

  return (
    <div className="calendar-modal-overlay">
      <div className="calendar-container">
        <div className="calendar-header">
          <h2 className="calendar-title">Calendar</h2>
          <button className="back-arrow-btn" onClick={onClose}>
            <img src="images/icons/calendar-back.svg" alt="back" />
          </button>
        </div>

        {/* Selected Date Box */}
        <div className="selected-date-section">
          <div className="selected-date-box">
            <span className="date-text">{selectedDate}</span>
            <div className="clear-date-group">
              <button className="clear-btn">X</button>
            </div>
          </div>
        </div>

        {/* Navigation */}
        <div className="calendar-nav-row">
          <button className="nav-btn" onClick={() => changeMonth(-1)}>
            <img src="images/icons/chevron-left.svg" alt="prev" />
          </button>
          <div className="current-month-display">
            {monthName} {year}
          </div>
          <button className="nav-btn" onClick={() => changeMonth(1)}>
            <img src="images/icons/chevron-right.svg" alt="next" />
          </button>
        </div>

        {/* Days Header */}
        <div className="days-grid-header">
          {daysOfWeek.map((day) => (
            <span key={day}>{day}</span>
          ))}
        </div>

        {/* Dates Grid */}
        <div className="calendar-grid">
          {dates.map((date, index) => (
            <div
              key={index}
              className={`calendar-date 
                ${date === 6 && month === 5 && year === 2023 ? "active-date" : ""} 
                ${date === "" ? "empty" : ""}`}
            >
              {date}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default CalendarOverlay;
